internal import Combine////  EditTransactionViewModel.swift//  FinanceApp////  Created by user271129 on 5/28/26.//import Foundationfinal class EditTransactionViewModel: ObservableObject {    @Published var accounts: [Account] = []    @Published var selectedAccountId: UUID? = nil    @Published var categories: [Category] = []    @Published var selectedCategory: Category? = nil    @Published var amount: Decimal = 0    @Published var description: String = ""    @Published var date: Date = Date()    @Published var isExpense: Bool = true    var selectedAccount: Account? {        accounts.first { $0.id == selectedAccountId }    }        init(isExpense: Bool) {        self.isExpense = isExpense    }    func load() async {        do {            // 1. Загружаем счета            let accountDtos = try await AccountService.shared.getAll()            let loadedAccounts = accountDtos.map { $0.toModel() }            // 2. Загружаем категории            let categoryDtos = try await CategoryService.shared.getByType(                isExpense ? .expense : .income            )            let loadedCategories = categoryDtos.map { $0.toModel() }            await MainActor.run {                self.accounts = loadedAccounts                self.categories = loadedCategories                // 3. Если счёт не выбран — выбираем первый                if self.selectedAccountId == nil {                    self.selectedAccountId = self.accounts.first?.id                }            }        } catch {            print("Ошибка загрузки данных:", error)        }    }    func save() async throws {        guard let account = selectedAccount else { return }        guard let category = selectedCategory else { return }        let dto = CreateTransactionDto(            type: isExpense ? .expense : .income,            accountId: account.id,            categoryId: category.id,            amount: amount,            description: description.isEmpty ? nil : description,            date: date        )        _ = try await TransactionService.shared.create(dto)    }}